/**
 * TalentDrawDemoDataDataWeightedPool
 * 加权随机池 - Generated by Rune Weaver
 * 
 * Features:
 * - drawMode: multiple_without_replacement
 * - duplicatePolicy: forbid
 * - poolStateTracking: session
 */

interface TalentEntry {
  id: string;
  label: string;
  description: string;
  weight: number;
  tier?: string;
}

interface WeightedItem<T> {
  item: T;
  weight: number;
  tier?: number;
}

export class TalentDrawDemoDataDataWeightedPool<T extends TalentEntry = TalentEntry> {
  private static instance?: TalentDrawDemoDataDataWeightedPool<any>;
  private items: WeightedItem<T>[] = [];
  private totalWeight: number = 0;

  // Session state (poolStateTracking="session")
  private sessionState: {
    remainingTalentIds: string[];
    ownedTalentIds: string[];
    currentChoiceIds: string[];
  } = {
    remainingTalentIds: [],
    ownedTalentIds: [],
    currentChoiceIds: [],
  };

  static getInstance<U extends TalentEntry = TalentEntry>(): TalentDrawDemoDataDataWeightedPool<U> {
    if (!TalentDrawDemoDataDataWeightedPool.instance) {
      TalentDrawDemoDataDataWeightedPool.instance = new TalentDrawDemoDataDataWeightedPool<U>();
    }
    return TalentDrawDemoDataDataWeightedPool.instance as TalentDrawDemoDataDataWeightedPool<U>;
  }

  constructor() {
    // Initialize with case-specific entries
    const initialEntries = [
    { id: "R001", label: "Strength Boost", description: "+10 Strength", weight: 40, tier: "R" },
    { id: "R002", label: "Fortitude", description: "+10 Strength", weight: 40, tier: "R" },
    { id: "SR001", label: "Agility Boost", description: "+10 Agility", weight: 30, tier: "SR" },
    { id: "SR002", label: "Swift Reflexes", description: "+10 Agility", weight: 30, tier: "SR" },
    { id: "SSR001", label: "Intelligence Boost", description: "+10 Intelligence", weight: 20, tier: "SSR" },
    { id: "UR001", label: "Ultimate Growth", description: "+10 All Attributes", weight: 10, tier: "UR" }
    ] as T[];
    for (const entry of initialEntries) {
      this.add(entry, entry.weight, entry.tier ? this.tierToNumber(entry.tier) : 0);
    }
    // Initialize session state with all entry IDs
    this.sessionState.remainingTalentIds = initialEntries.map(e => e.id);
    this.sessionState.ownedTalentIds = [];
    this.sessionState.currentChoiceIds = [];

  }

  private tierToNumber(tier: string): number {
    const tierMap: Record<string, number> = { 'R': 1, 'SR': 2, 'SSR': 3, 'UR': 4 };
    return tierMap[tier] || 1;
  }

  /**
   * 添加条目
   */
  add(item: T, weight: number, tier?: number): void {
    this.items.push({ item, weight, tier });
    this.totalWeight += weight;
  }

  /**
   * 移除条目
   */
  remove(item: T): boolean {
    const index = this.items.findIndex(i => i.item === item);
    if (index === -1) return false;

    this.totalWeight -= this.items[index].weight;
    this.items.splice(index, 1);
    return true;
  }

  /**
   * 清空池子
   */
  clear(): void {
    this.items = [];
    this.totalWeight = 0;
  }

  /**
   * 按权重随机抽取一个
   */
  draw(): T | null {
    if (this.items.length === 0 || this.totalWeight <= 0) {
      return null;
    }

    let random = RandomFloat(0, this.totalWeight);

    for (const item of this.items) {
      random -= item.weight;
      if (random <= 0) {
        return item.item;
      }
    }

    return this.items[this.items.length - 1]?.item || null;
  }

  /**
   * 按权重随机抽取多个（不重复）
   */
  drawMultiple(count: number): T[] {
    const result: T[] = [];
    const tempPool = new TalentDrawDemoDataDataWeightedPool<T>();

    // 复制所有条目
    for (const item of this.items) {
      tempPool.add(item.item, item.weight, item.tier);
    }

    // 抽取指定数量
    for (let i = 0; i < count && i < this.items.length; i++) {
      const drawn = tempPool.draw();
      if (drawn !== null) {
        result.push(drawn);
        tempPool.remove(drawn);
      }
    }

    return result;
  }

  /**
   * Draw multiple candidates for selection (without replacement)
   * Supports duplicatePolicy="forbid" to prevent duplicates
   */
  drawForSelection(count: number = 3): T[] {
    if (this.items.length === 0) {
      print(`[Rune Weaver] TalentDrawDemoDataDataWeightedPool: No items in pool`);
      return [];
    }

    const result: T[] = [];
    const drawnIds = new Set<string>();
    const availableItems = this.items.filter(item => 
      this.sessionState.remainingTalentIds.includes((item.item as any).id)
    );

    if (availableItems.length === 0) {
      print(`[Rune Weaver] TalentDrawDemoDataDataWeightedPool: No available items in session pool`);
      return [];
    }

    for (let i = 0; i < count && availableItems.length > 0; i++) {
      // Check duplicate policy
      if ("forbid" === "forbid" && drawnIds.size >= availableItems.length) {
        print(`[Rune Weaver] TalentDrawDemoDataDataWeightedPool: Cannot draw more unique items (duplicatePolicy="forbid")`);
        break;
      }

      // Calculate total weight of current available items for each draw
      const currentTotalWeight = availableItems.reduce((sum, item) => sum + item.weight, 0);

      if (currentTotalWeight <= 0) {
        print(`[Rune Weaver] TalentDrawDemoDataDataWeightedPool: No weight available in pool`);
        break;
      }

      let random = RandomFloat(0, currentTotalWeight);
      let drawnItem: WeightedItem<T> | null = null;

      for (const item of availableItems) {
        random -= item.weight;
        if (random <= 0) {
          drawnItem = item;
          break;
        }
      }

      if (drawnItem) {
        const itemId = (drawnItem.item as any).id;

        // Check for duplicates if policy is "forbid"
        if ("forbid" === "forbid" && drawnIds.has(itemId)) {
          // Skip this draw and try again
          i--;
          continue;
        }

        result.push(drawnItem.item);
        drawnIds.add(itemId);

        // Remove from available items for this draw session
        const index = availableItems.indexOf(drawnItem);
        if (index > -1) {
          availableItems.splice(index, 1);
        }
      }
    }

    // Update currentChoiceIds in session state
    this.sessionState.currentChoiceIds = result.map(item => (item as any).id);

    return result;
  }

  /**
   * Commit player selection
   * Remove selected item from remainingTalentIds
   * Add selected item to ownedTalentIds
   */
  commitSelection(selectedId: string): void {
    // Remove from remaining
    const remainingIndex = this.sessionState.remainingTalentIds.indexOf(selectedId);
    if (remainingIndex > -1) {
      this.sessionState.remainingTalentIds.splice(remainingIndex, 1);
    }

    // Add to owned
    if (!this.sessionState.ownedTalentIds.includes(selectedId)) {
      this.sessionState.ownedTalentIds.push(selectedId);
    }

    // Clear current choices
    this.sessionState.currentChoiceIds = [];

    print(`[Rune Weaver] TalentDrawDemoDataDataWeightedPool: Committed selection ${selectedId}, remaining: ${this.sessionState.remainingTalentIds.length}`);
  }

  /**
   * Get remaining talent IDs in session
   */
  getRemainingTalentIds(): string[] {
    return [...this.sessionState.remainingTalentIds];
  }

  /**
   * Get owned talent IDs in session
   */
  getOwnedTalentIds(): string[] {
    return [...this.sessionState.ownedTalentIds];
  }

  /**
   * Get current choice IDs in session
   */
  getCurrentChoiceIds(): string[] {
    return [...this.sessionState.currentChoiceIds];
  }

  /**
   * Reset session state
   */
  resetSessionState(): void {
    this.sessionState.remainingTalentIds = this.items.map(item => (item.item as any).id);
    this.sessionState.ownedTalentIds = [];
    this.sessionState.currentChoiceIds = [];
    print(`[Rune Weaver] TalentDrawDemoDataDataWeightedPool: Session state reset`);
  }

  /**
   * 按 tier 过滤后抽取
   */
  drawByTier(tier: number): T | null {
    const tierItems = this.items.filter(i => i.tier === tier);
    if (tierItems.length === 0) return null;

    const tierTotalWeight = tierItems.reduce((sum, i) => sum + i.weight, 0);
    let random = RandomFloat(0, tierTotalWeight);

    for (const item of tierItems) {
      random -= item.weight;
      if (random <= 0) {
        return item.item;
      }
    }

    return tierItems[tierItems.length - 1]?.item || null;
  }

  /**
   * 获取所有条目
   */
  getAllItems(): WeightedItem<T>[] {
    return [...this.items];
  }

  /**
   * 获取条目数量
   */
  getCount(): number {
    return this.items.length;
  }
}

/**
 * 注册函数 - 由 Bridge 调用
 */
export function registerTalentDrawDemoDataDataWeightedPool(): void {
  TalentDrawDemoDataDataWeightedPool.getInstance();
  print("[Rune Weaver] TalentDrawDemoDataDataWeightedPool registered");
}

/**
 * TalentDrawDemoRuleRuleSelectionFlow
 * 选择流程管理器 - Generated by Rune Weaver
 *
 * Features:
 * - triggerKey: "F4"
 * - choiceCount: 3
 * - selectionPolicy: "single"
 * - applyMode: "immediate"
 * - postSelectionPoolBehavior: "remove_selected_from_remaining"
 * - trackSelectedItems: true
 * - Apply effect immediately
 * 
 */

interface SelectionOption {
  id: string;
  name: string;
  description: string;
  icon?: string;
  tier?: string;
}

interface PoolCandidate {
  id: string;
  name?: string;
  label?: string;
  description?: string;
  icon?: string;
  tier?: string;
}

interface PlayerSelection {
  playerId: number;
  options: SelectionOption[];
  selectedIndex: number;
  isConfirmed: boolean;
  deferredEffect?: SelectionOption;
}

export class TalentDrawDemoRuleRuleSelectionFlow {
  private static instance: TalentDrawDemoRuleRuleSelectionFlow;
  private activeSelections: Map<number, PlayerSelection> = new Map();
  private selectionCallbacks: Map<number, (option: SelectionOption) => void> = new Map();

  private playerSessionStates: Map<number, {
    remainingIds: string[];
    ownedIds: string[];
    currentChoiceIds: string[];
  }> = new Map();

  private rarityAttributeBonusMap: Record<string, { attribute: string; value: number }> = {
      "R": { attribute: "strength", value: 10 },
      "SR": { attribute: "agility", value: 10 },
      "SSR": { attribute: "intelligence", value: 10 },
      "UR": { attribute: "all", value: 10 }
  };


  static getInstance(): TalentDrawDemoRuleRuleSelectionFlow {
    if (!TalentDrawDemoRuleRuleSelectionFlow.instance) {
      TalentDrawDemoRuleRuleSelectionFlow.instance = new TalentDrawDemoRuleRuleSelectionFlow();
    }
    return TalentDrawDemoRuleRuleSelectionFlow.instance;
  }

  initPlayerSession(playerId: number, allIds: string[]): void {
    this.playerSessionStates.set(playerId, {
      remainingIds: [...allIds],
      ownedIds: [],
      currentChoiceIds: [],
    });
    print(`[Rune Weaver] TalentDrawDemoRuleRuleSelectionFlow: Initialized session for player ${playerId}`);
  }

  getPlayerSession(
    playerId: number
  ): { remainingIds: string[]; ownedIds: string[]; currentChoiceIds: string[] } | undefined {
    return this.playerSessionStates.get(playerId);
  }

  private removeFromRemaining(playerId: number, optionId: string): void {
    const session = this.playerSessionStates.get(playerId);
    if (!session) return;

    const index = session.remainingIds.indexOf(optionId);
    if (index > -1) {
      session.remainingIds.splice(index, 1);
    }
  }

  private addToOwned(playerId: number, optionId: string): void {
    const session = this.playerSessionStates.get(playerId);
    if (!session) return;

    if (!session.ownedIds.includes(optionId)) {
      session.ownedIds.push(optionId);
    }
  }

  private updateCurrentChoices(playerId: number, choiceIds: string[]): void {
    const session = this.playerSessionStates.get(playerId);
    if (!session) return;
    session.currentChoiceIds = [...choiceIds];
  }

  startSelection(
    playerId: number,
    options: SelectionOption[],
    onSelected: (option: SelectionOption) => void
  ): void {
    if (options.length === 0) {
      print("[Rune Weaver] Cannot start selection with empty options");
      return;
    }

    this.activeSelections.set(playerId, {
      playerId,
      options,
      selectedIndex: -1,
      isConfirmed: false,
    });
    this.selectionCallbacks.set(playerId, onSelected);

    this.updateCurrentChoices(playerId, options.map((option) => option.id));
    this.sendToClient(playerId, options);
  }

  onPlayerSelect(playerId: number, optionIndex: number): void {
    const selection = this.activeSelections.get(playerId);
    if (!selection) return;
    if (optionIndex < 0 || optionIndex >= selection.options.length) return;

    selection.selectedIndex = optionIndex;
    this.fireSelectionEvent(playerId, selection.options[optionIndex]);
  }

  onPlayerConfirm(playerId: number): void {
    const selection = this.activeSelections.get(playerId);
    if (!selection || selection.selectedIndex === -1) return;

    selection.isConfirmed = true;
    const selectedOption = selection.options[selection.selectedIndex];

    this.removeFromRemaining(playerId, selectedOption.id);
    this.addToOwned(playerId, selectedOption.id);

    this.applyEffectByRarity(playerId, selectedOption);


    const callback = this.selectionCallbacks.get(playerId);
    if (callback) {
      callback(selectedOption);
    }

    this.fireConfirmationEvent(playerId, selectedOption);
    this.activeSelections.delete(playerId);
    this.selectionCallbacks.delete(playerId);
  }

  private applyEffectByRarity(playerId: number, option: SelectionOption): void {
    const hero = PlayerResource.GetSelectedHeroEntity(playerId as PlayerID);
    if (!hero) {
      print(`[Rune Weaver] TalentDrawDemoRuleRuleSelectionFlow: No hero found for player ${playerId}`);
      return;
    }

    const DEFAULT_RARITY = "R";
    const rarity = option.tier || DEFAULT_RARITY;
    const bonusConfig = this.rarityAttributeBonusMap[rarity];
    if (!bonusConfig) {
      print(`[Rune Weaver] TalentDrawDemoRuleRuleSelectionFlow: No bonus config for rarity ${rarity}`);
      return;
    }

    const { attribute, value } = bonusConfig;
    switch (attribute) {
      case "strength":
        hero.ModifyStrength(value);
        break;
      case "agility":
        hero.ModifyAgility(value);
        break;
      case "intelligence":
        hero.ModifyIntellect(value);
        break;
      case "all":
        hero.ModifyStrength(value);
        hero.ModifyAgility(value);
        hero.ModifyIntellect(value);
        break;
      default:
        print(`[Rune Weaver] TalentDrawDemoRuleRuleSelectionFlow: Unknown attribute ${attribute}`);
    }

    this.fireEffectAppliedEvent(playerId, option, bonusConfig);
  }

  private fireEffectAppliedEvent(
    playerId: number,
    option: SelectionOption,
    bonusConfig: { attribute: string; value: number }
  ): void {
    if (CustomGameEventManager) {
      (CustomGameEventManager.Send_ServerToPlayer as any)(
        PlayerResource.GetPlayer(playerId as PlayerID),
        "rune_weaver_effect_applied",
        {
          featureId: "talent_draw_demo",
          optionId: option.id,
          optionName: option.name,
          attribute: bonusConfig.attribute,
          value: bonusConfig.value,
          rarity: option.tier || "R",
        }
      );
    }
  }

  private fireSelectionEvent(playerId: number, option: SelectionOption): void {
    if (CustomGameEventManager) {
      (CustomGameEventManager.Send_ServerToPlayer as any)(
        PlayerResource.GetPlayer(playerId as PlayerID),
        "rune_weaver_selection_made",
        {
          featureId: "talent_draw_demo",
          optionId: option.id,
          optionName: option.name,
          rarity: option.tier || "R",
        }
      );
    }
  }

  private fireConfirmationEvent(playerId: number, option: SelectionOption): void {
    if (CustomGameEventManager) {
      (CustomGameEventManager.Send_ServerToPlayer as any)(
        PlayerResource.GetPlayer(playerId as PlayerID),
        "rune_weaver_selection_confirmed",
        {
          featureId: "talent_draw_demo",
          optionId: option.id,
          optionName: option.name,
          rarity: option.tier || "R",
          timestamp: GameRules.GetGameTime(),
        }
      );
    }
  }

  private sendToClient(playerId: number, options: SelectionOption[]): void {
    if ((GameRules as any).XNetTable) {
      (GameRules as any).XNetTable.SetTableValue(
        "rune_weaver_selection",
        `player_${playerId}_feature_talent_draw_demo`,
        { featureId: "talent_draw_demo", options, status: "waiting" }
      );
    }

    if (CustomGameEventManager) {
      const payload = {
        featureId: "talent_draw_demo",
        options,
        choiceCount: 3,
        selectionPolicy: "single",
        title: "Choose Your Talent",
        description: "Press F4 to open talent draw",
      };
      const player = PlayerResource.GetPlayer(playerId as PlayerID);
      print(`[Rune Weaver] TalentDrawDemoRuleRuleSelectionFlow: Sending selection UI to player ${playerId}, options=${options.length}, player=${player ? "ok" : "missing"}`);
      if (player) {
        (CustomGameEventManager.Send_ServerToPlayer as any)(
          player,
          "rune_weaver_show_selection",
          payload
        );
      } else {
        (CustomGameEventManager.Send_ServerToAllClients as any)(
          "rune_weaver_show_selection",
          payload
        );
      }
    }
  }

  generateOptionsFromPool<T extends SelectionOption>(
    playerId: number,
    pool: any,
    count: number
  ): T[] {
    const normalizeCandidates = (candidates: PoolCandidate[]): T[] => {
      const options = candidates.map((candidate) => ({
        id: candidate.id,
        name: candidate.name || candidate.label || candidate.id,
        description: candidate.description || "",
        icon: candidate.icon,
        tier: candidate.tier,
      })) as T[];

      return options;
    };

    if (pool && typeof pool.drawForSelection === "function") {
      const candidates = normalizeCandidates(pool.drawForSelection(count) as PoolCandidate[]);
      const candidateIds: string[] = [];
      for (const candidate of candidates as T[]) {
        candidateIds.push(candidate.id);
      }
      this.updateCurrentChoices(playerId, candidateIds);
      return candidates;
    }

    if (pool && typeof pool.drawMultiple === "function") {
      return normalizeCandidates(pool.drawMultiple(count) as PoolCandidate[]);
    }

    return [];
  }

  triggerSelectionFromPool(playerId: number, pool: any): void {
    if (!pool) {
      print(`[Rune Weaver] TalentDrawDemoRuleRuleSelectionFlow: No pool available`);
      return;
    }


    if (!this.getPlayerSession(playerId) && typeof this.initPlayerSession === "function") {
      const remainingIds: string[] =
        typeof pool.getRemainingTalentIds === "function"
          ? pool.getRemainingTalentIds()
          : (() => {
              const ids: string[] = [];
              if (typeof pool.getAllItems === "function") {
                for (const item of pool.getAllItems()) {
                  ids.push(item.item.id);
                }
              }
              return ids;
            })();
      if (remainingIds.length > 0) {
        this.initPlayerSession(playerId, remainingIds);
      }
    }


    const options = this.generateOptionsFromPool(playerId, pool, 3);
    if (!options || options.length === 0) {
      print(`[Rune Weaver] TalentDrawDemoRuleRuleSelectionFlow: No options generated for player ${playerId}`);
      return;
    }

    this.startSelection(playerId, options, (selectedOption) => {
      if (pool && typeof pool.commitSelection === "function") {
        pool.commitSelection(selectedOption.id);
      }
    });
  }
}

